def solve(input_string):
    if not isinstance(input_string, str):
        return {}

    char_count = {}
    for char in input_string:
        if char in char_count:
            char_count[char] += 1
        else:
            char_count[char] = 1

    return dict(sorted(char_count.items()))

# Minimal unit tests
def test_solve():
    assert solve("hello") == {'e': 1, 'h': 1, 'l': 2, 'o': 1}
    assert solve("aabbcc") == {'a': 2, 'b': 2, 'c': 2}
    assert solve("") == {}
    assert solve("abc") == {'a': 1, 'b': 1, 'c': 1}
    assert solve("aA") == {'A': 1, 'a': 1}
    assert solve("123321") == {'1': 2, '2': 2, '3': 2}
    assert solve(None) == {}
    assert solve(123) == {}

test_solve()
